  `Witness2_PersonalID` varchar(13) NOT NULL,
  `Witness2_Occupation` varchar(45) NOT NULL,
  `Witness2_Nationality` varchar(25) NOT NULL,
  `Witness2_Sex` enum('Masculino','Femenino') NOT NULL,
  `Witness2_CivilStatus` varchar(15) NOT NULL,
  `Witness2_Address` text NOT NULL,
  `Guarantor1_Name` varchar(100) NOT NULL,
  `Guarantor1_PersonalID` varchar(13) NOT NULL,
  `Guarantor1_Occupation` varchar(45) NOT NULL,
