CREATE TABLE `customer` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `customer_id` int(10) unsigned NOT NULL,
  `company_id` int(11) DEFAULT 1,
  `customer_first_name` varchar(245) NOT NULL DEFAULT '',
  `customer_nickname` varchar(20) DEFAULT '',
  `customer_personalid` varchar(13) DEFAULT NULL,
  `customer_birthdate` varchar(15) NOT NULL,
  `customer_nationality` varchar(45) NOT NULL DEFAULT 'dominicano',
  `customer_civilstatus` varchar(11) DEFAULT '',
  `customer_gender` varchar(9) DEFAULT '',
  `customer_address` varchar(100) DEFAULT '',
  `customer_city` int(11) DEFAULT NULL,
  `customer_district` int(11) DEFAULT NULL,
  `customer_zipcode` varchar(5) DEFAULT '',
  `customer_email` varchar(45) DEFAULT '',
  `customer_phone` varchar(15) DEFAULT '',
  `customer_mobile` varchar(15) DEFAULT '',
  `customer_workaddress` varchar(100) DEFAULT '',
  `customer_workcity` int(11) DEFAULT NULL,
  `customer_workdistrict` int(11) DEFAULT NULL,
  `customer_workzipcode` varchar(5) DEFAULT '',
  `customer_workemail` varchar(45) DEFAULT '',
  `customer_workplace` varchar(45) DEFAULT '',
  `customer_occupation` varchar(50) DEFAULT '',
