CREATE TABLE `loans` (
  `loans_id` int(11) NOT NULL AUTO_INCREMENT,
  `loans_no` int(11) NOT NULL,
  `company_id` int(11) NOT NULL DEFAULT 1,
  `user_id` int(11) NOT NULL,
  `contract_number` varchar(8) NOT NULL,
  `entry_date` date DEFAULT NULL,
  `entry_time` time NOT NULL,
  `loanstype_id` int(11) NOT NULL,
  `duration` int(10) unsigned DEFAULT 13,
  `start_date` date NOT NULL,
  `loans_amount` double NOT NULL DEFAULT 0,
  `end_date` date NOT NULL,
  `due_amount` double NOT NULL DEFAULT 0,
  `cuota` double NOT NULL DEFAULT 0,
  `capital` double NOT NULL DEFAULT 0,
  `interes` double NOT NULL DEFAULT 0,
  `interes_amount` double NOT NULL DEFAULT 0,
  `interes_nogain` double NOT NULL DEFAULT 0,
  `interes_gain` double NOT NULL DEFAULT 0,
  `balance` double NOT NULL DEFAULT 0,
  `customer_id` int(11) NOT NULL,
  `routes_id` int(11) NOT NULL,
  `collector_id` int(11) DEFAULT NULL,
  `codgarante` int(11) DEFAULT NULL,
  `return_p` char(3) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT 'NO',
  `FechaFinalizado` date DEFAULT NULL,
  `create_date` timestamp NULL DEFAULT current_timestamp(),
  `active` char(3) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  PRIMARY KEY (`loans_id`),
  UNIQUE KEY `codprestamo_UNIQUE` (`loans_no`)
) ENGINE=InnoDB AUTO_INCREMENT=266 DEFAULT CHARSET=latin1 COLLATE=latin1_spanish_ci;






